// ---------------------------------------------------------------------------
// Orchestrator — media-pipeline-${trial_id}
//
// Flow:
//   download-task
//       ↓
//   process-task
//       ↓
//   upload-task (primary)  ──┐
//   upload-task (extra[0]) ──┤  ← batch.triggerByTaskAndWait (parallel)
//   upload-task (extra[1]) ──┘
// ---------------------------------------------------------------------------

export const mediaPipeline = task({
  id: "media-pipeline",
  // The trial_id is embedded in the run payload; every log line carries it
  // for full traceability across the pipeline steps.
  run: async (payload: PipelinePayload): Promise<PipelineResult> => {
    const { trial_id, sourceUrl, extraDestinations = [] } = payload;

    logger.info(`media-pipeline-${trial_id}: initialising`, {
      trial_id,
      sourceUrl,
    });

    try {
      // ── Step 1: Download ──────────────────────────────────────────────────
      logger.info(`media-pipeline-${trial_id}: step 1 — triggering download-task`);

      const downloadRun = await downloadTask.triggerAndWait({
        sourceUrl,
        trial_id,
      });

      if (!downloadRun.ok) {
        throw new Error(
          `download-task failed: ${downloadRun.error ?? "unknown error"}`
        );
      }

      const downloadResult = downloadRun.output;
      logger.info(`media-pipeline-${trial_id}: step 1 complete`, props(downloadResult));

      // ── Step 2: Process ───────────────────────────────────────────────────
      logger.info(`media-pipeline-${trial_id}: step 2 — triggering process-task`);

      const processRun = await processTask.triggerAndWait({
        trial_id: downloadResult.trial_id,
        localPath: downloadResult.localPath,
        mimeType: downloadResult.mimeType,
      });

      if (!processRun.ok) {
        throw new Error(
          `process-task failed: ${processRun.error ?? "unknown error"}`
        );
      }

      const processResult = processRun.output;
      logger.info(`media-pipeline-${trial_id}: step 2 complete`, props(processResult));

      // ── Step 3: Upload (primary + optional parallel extras) ───────────────
      logger.info(`media-pipeline-${trial_id}: step 3 — triggering upload task(s)`);

      const primaryDestination = "cdn.example.com";
      const allDestinations = [primaryDestination, ...extraDestinations];

      let uploadResults: UploadResult[];

      if (allDestinations.length === 1) {
        // ── Single destination: simple triggerAndWait ────────────────────────
        const uploadRun = await uploadTask.triggerAndWait({
          trial_id: processResult.trial_id,
          processedPath: processResult.processedPath,
          destination: primaryDestination,
          metadata: processResult.metadata,
        });

        if (!uploadRun.ok) {
          throw new Error(
            `upload-task failed: ${uploadRun.error ?? "unknown error"}`
          );
        }

        uploadResults = [uploadRun.output];
      } else {
        // ── Multiple destinations: fire all uploads in parallel ───────────────
        // batch.triggerByTaskAndWait dispatches every item concurrently and
        // resolves only when ALL runs have finished (success or failure).
        const batchResult = await batch.triggerByTaskAndWait(
          allDestinations.map((destination) => ({
            task: uploadTask,
            payload: {
              trial_id: processResult.trial_id,
              processedPath: processResult.processedPath,
              destination,
              metadata: processResult.metadata,
            } satisfies UploadPayload,
          }))
        );

        // Surface any individual upload failures as a single combined error.
        const failures = batchResult.runs.filter((r) => !r.ok);
        if (failures.length > 0) {
          const messages = failures
            .map((f) =>
              f.ok === false
                ? `destination=${f.taskIdentifier} error=${String(f.error)}`
                : "unknown failure"
            )
            .join("; ");
          throw new Error(`One or more upload-task runs failed — ${messages}`);
        }

        uploadResults = batchResult.runs
          .filter((r): r is typeof r & { ok: true } => r.ok)
          .map((r) => r.output as UploadResult);
      }

      logger.info(`media-pipeline-${trial_id}: step 3 complete`, {
        uploadCount: uploadResults.length,
        destinations: uploadResults.map((u) => u.destination),
      });

      // ── Pipeline success ──────────────────────────────────────────────────
      logger.info(`media-pipeline-${trial_id}: all steps succeeded`);

      return {
        trial_id,
        status: "success",
        uploads: uploadResults,
      };
    } catch (err: unknown) {
      // ── Centralised error handler ─────────────────────────────────────────
      const message = err instanceof Error ? err.message : String(err);

      logger.error(`media-pipeline-${trial_id}: pipeline failed`, {
        trial_id,
        error: message,
      });

      return {
        trial_id,
        status: "failure",
        error: message,
      };
    }
  },
});

import { task, batch, logger } from "@trigger.dev/sdk/v3";

// ---------------------------------------------------------------------------
// Shared payload / result types
// ---------------------------------------------------------------------------

export interface DownloadPayload {
  sourceUrl: string;
  trial_id: string;
}

export interface DownloadResult {
  trial_id: string;
  localPath: string;
  fileSizeBytes: number;
  mimeType: string;
}

export interface ProcessPayload {
  trial_id: string;
  localPath: string;
  mimeType: string;
}

export interface ProcessResult {
  trial_id: string;
  processedPath: string;
  durationMs: number;
  metadata: Record<string, unknown>;
}

export interface UploadPayload {
  trial_id: string;
  processedPath: string;
  destination: string;
  metadata: Record<string, unknown>;
}

export interface UploadResult {
  trial_id: string;
  destination: string;
  publicUrl: string;
  uploadedAt: string;
}

export interface PipelinePayload {
  trial_id: string;
  sourceUrl: string;
  /** Additional upload destinations beyond the primary one (triggers parallel uploads). */
  extraDestinations?: string[];
}

export type PipelineStatus = "success" | "failure";

export interface PipelineResult {
  trial_id: string;
  status: PipelineStatus;
  uploads?: UploadResult[];
  error?: string;
}

// ---------------------------------------------------------------------------
// Helper: cast a typed result to the Record<string, unknown> that the
// Trigger.dev logger expects for its structured-log properties argument.
// ---------------------------------------------------------------------------
function props(obj: unknown): Record<string, unknown> {
  return obj as Record<string, unknown>;
}

// ---------------------------------------------------------------------------
// Step 1 — Download task
// ---------------------------------------------------------------------------

export const downloadTask = task({
  id: "download-task",
  run: async (payload: DownloadPayload): Promise<DownloadResult> => {
    logger.info("download-task: starting", {
      trial_id: payload.trial_id,
      sourceUrl: payload.sourceUrl,
    });

    // TODO: replace with real download logic (e.g. fetch + stream to disk / S3)
    const result: DownloadResult = {
      trial_id: payload.trial_id,
      localPath: `/tmp/${payload.trial_id}/source`,
      fileSizeBytes: 0,
      mimeType: "application/octet-stream",
    };

    logger.info("download-task: complete", props(result));
    return result;
  },
});

// ---------------------------------------------------------------------------
// Step 2 — Process task
// ---------------------------------------------------------------------------

export const processTask = task({
  id: "process-task",
  run: async (payload: ProcessPayload): Promise<ProcessResult> => {
    logger.info("process-task: starting", {
      trial_id: payload.trial_id,
      localPath: payload.localPath,
    });

    const start = Date.now();

    // TODO: replace with real media-processing logic (transcode, resize, analyse…)
    const result: ProcessResult = {
      trial_id: payload.trial_id,
      processedPath: `/tmp/${payload.trial_id}/processed`,
      durationMs: Date.now() - start,
      metadata: { codec: "h264", resolution: "1920x1080" },
    };

    logger.info("process-task: complete", props(result));
    return result;
  },
});

